1	<?php
2	declare(strict_types=1);
3	
4	namespace app\service;
5	
6	use think\facade\Db;
7	
8	/**
9	 * Payment posting with idempotency and invoice status update.
10	 */
11	class PaymentService
12	{
13	    private const IDEMP_WINDOW_SECONDS = 600; // 10 minutes
14	
15	    public static function post(array $data, array $user, string $idempotencyKey, string $traceId = ''): array
16	    {
17	        $invoiceId = (int)($data['invoice_id'] ?? 0);
18	        $amountCents = (int)($data['amount_cents'] ?? 0);
19	        $paidAt = $data['paid_at'] ?? date('Y-m-d H:i:s');
20	        $method = $data['method'] ?? 'cash';
21	
22	        if ($invoiceId <= 0) throw new \think\exception\HttpException(400, 'invoice_id is required');
23	        if ($amountCents <= 0) throw new \think\exception\HttpException(400, 'amount_cents must be positive');
24	
25	        $scopeKey = self::buildScopeKey('POST', '/payments', $user['id'], $idempotencyKey);
26	        $parts = explode('|', $scopeKey);
27	        $cutoff = date('Y-m-d H:i:s', time() - self::IDEMP_WINDOW_SECONDS);
28	
29	        // ── Atomic idempotency: reserve-first within a transaction ──
30	        // The UNIQUE KEY (actor_id, method, route, idempotency_key) on
31	        // payment_idempotency acts as the concurrency gate.  We attempt
32	        // to INSERT the reservation row FIRST.  If a concurrent request
33	        // already reserved the same key, the INSERT fails with a
34	        // duplicate-key error and we deterministically replay the
35	        // original stored response.
36	
37	        Db::startTrans();
38	        try {
39	            // 1. Check for an existing replay within the 10-minute window
40	            $existing = Db::table('payment_idempotency')
41	                ->where('actor_id', (int)$parts[2])
42	                ->where('method', $parts[0])
43	                ->where('route', $parts[1])
44	                ->where('idempotency_key', $parts[3])
45	                ->where('created_at', '>=', $cutoff)
46	                ->lock(true) // SELECT … FOR UPDATE — serialises concurrent reads
47	                ->find();
48	
49	            if ($existing) {
50	                Db::commit();
51	                return json_decode($existing['response_json'], true);
52	            }
53	
54	            // 2. Reserve the idempotency slot (placeholder response).
55	            //    The UNIQUE constraint prevents two concurrent requests
56	            //    from both reserving the same key.
57	            try {
58	                Db::table('payment_idempotency')->insert([
59	                    'actor_id'        => (int)$parts[2],
60	                    'method'          => $parts[0],
61	                    'route'           => $parts[1],
62	                    'idempotency_key' => $parts[3],
63	                    'response_status' => 0,
64	                    'response_json'   => '{}',
65	                ]);
66	            } catch (\Throwable $dupEx) {
67	                // Another request reserved first — replay its response
68	                Db::commit();
69	                $replay = Db::table('payment_idempotency')
70	                    ->where('actor_id', (int)$parts[2])
71	                    ->where('method', $parts[0])
72	                    ->where('route', $parts[1])
73	                    ->where('idempotency_key', $parts[3])
74	                    ->where('created_at', '>=', $cutoff)
75	                    ->find();
76	                if ($replay && $replay['response_status'] > 0) {
77	                    return json_decode($replay['response_json'], true);
78	                }
79	                throw new \think\exception\HttpException(409, 'Concurrent payment in progress');
80	            }
81	
82	            // 3. Verify invoice (inside the same transaction)
83	            $invoice = Db::table('invoices')->where('id', $invoiceId)->find();
84	            if (!$invoice) throw new \think\exception\HttpException(404, 'Invoice not found');
85	
86	            $contract = Db::table('contracts')->where('id', $invoice['contract_id'])->find();
87	            if (!$contract || !ScopeService::canAccess($user, $contract['geo_scope_level'], (int)$contract['geo_scope_id'])) {
88	                throw new \think\exception\HttpException(403, 'Invoice outside your scope');
89	            }
90	
91	            if ($invoice['status'] === 'paid') {
92	                throw new \think\exception\HttpException(409, 'Invoice already paid');
93	            }
94	
95	            // 4. Encrypt sensitive bank reference (AES-256 at rest)
96	            $reference = $data['reference'] ?? null;
97	            $referenceEnc = !empty($reference) ? EncryptionService::encrypt((string)$reference) : null;
98	
99	            // 5. Record payment
100	            $paymentId = Db::table('payments')->insertGetId([
101	                'invoice_id'    => $invoiceId,
102	                'amount_cents'  => $amountCents,
103	                'paid_at'       => $paidAt,
104	                'method'        => $method,
105	                'reference_enc' => $referenceEnc,
106	                'posted_by'     => $user['id'],
107	            ]);
108	
109	            // 6. Transition invoice to paid
110	            $beforeInvoice = ['status' => $invoice['status'], 'amount_cents' => $invoice['amount_cents']];
111	            InvoiceService::transition($invoiceId, 'paid', $traceId);
112	
113	            // 7. Compute final balance
114	            $totalPaid = (int)Db::table('payments')->where('invoice_id', $invoiceId)->sum('amount_cents');
115	            $totalRefunded = (int)Db::table('refunds')->where('invoice_id', $invoiceId)->sum('amount_cents');
116	            $balanceCents = (int)$invoice['amount_cents'] - $totalPaid + $totalRefunded;
117	
118	            $result = [
119	                'payment_id'     => $paymentId,
120	                'invoice_status' => 'paid',
121	                'balance_cents'  => max($balanceCents, 0),
122	            ];
123	
124	            // 8. Finalise idempotency record with the real response
125	            Db::table('payment_idempotency')
126	                ->where('actor_id', (int)$parts[2])
127	                ->where('method', $parts[0])
128	                ->where('route', $parts[1])
129	                ->where('idempotency_key', $parts[3])
130	                ->update([
131	                    'response_status' => 201,
132	                    'response_json'   => json_encode($result),
133	                ]);
134	
135	            Db::commit();
136	
137	            LogService::info('payment_posted', ['payment_id' => $paymentId, 'invoice_id' => $invoiceId], $traceId);
138	
139	            // Append-only audit log (prompt: payment actions with before/after values)
140	            AuditService::log(
141	                'payment_posted',
142	                (int)$user['id'],
143	                'invoice',
144	                $invoiceId,
145	                $beforeInvoice,
146	                ['status' => 'paid', 'payment_id' => $paymentId, 'amount_cents' => $amountCents, 'method' => $method, 'balance_cents' => max($balanceCents, 0)],
147	                RequestContext::ip(),
148	                RequestContext::device(),
149	                $traceId
150	            );
151	
152	            return $result;
153	        } catch (\Throwable $e) {
154	            Db::rollback();
155	            throw $e;
156	        }
157	    }
158	
159	    public static function getReceipt(int $invoiceId, array $user): array
160	    {
161	        $invoice = Db::table('invoices')->where('id', $invoiceId)->find();
162	        if (!$invoice) throw new \think\exception\HttpException(404, 'Invoice not found');
163	
164	        $contract = Db::table('contracts')->where('id', $invoice['contract_id'])->find();
165	        if (!$contract || !ScopeService::canAccess($user, $contract['geo_scope_level'], (int)$contract['geo_scope_id'])) {
166	            throw new \think\exception\HttpException(403, 'Outside your scope');
167	        }
168	
169	        $payments = Db::table('payments')->where('invoice_id', $invoiceId)->select()->toArray();
170	        return ['invoice' => $invoice, 'contract' => $contract, 'payments' => $payments];
171	    }
172	
173	    private static function buildScopeKey(string $method, string $route, int $actorId, string $key): string
174	    {
175	        return $method . '|' . $route . '|' . $actorId . '|' . $key;
176	    }
177	
178	}
