2	declare(strict_types=1);
3	
4	namespace app\controller;
5	
6	use think\Request;
7	use think\Response;
8	use app\service\PaymentService;
9	use app\service\RefundService;
10	use app\service\ExportService;
11	use app\service\AuthContext;
12	
13	class Payment
14	{
15	    /** POST /payments */
16	    public function create(Request $request): Response
17	    {
18	        $traceId = \app\middleware\TraceId::getId();
19	        $user = AuthContext::user();
20	        $idempotencyKey = $_SERVER['HTTP_IDEMPOTENCY_KEY'] ?? '';
21	
22	        if (empty($idempotencyKey)) {
23	            throw new \think\exception\HttpException(400, 'Idempotency-Key header is required');
24	        }
25	
26	        $result = PaymentService::post($request->post(), $user, $idempotencyKey, $traceId);
27	        return json($result, 201);
28	    }
29	
30	    /** POST /refunds */
31	    public function refund(Request $request): Response
32	    {
33	        $traceId = \app\middleware\TraceId::getId();
34	        $user = AuthContext::user();
35	        $result = RefundService::create($request->post(), $user, $traceId);
36	        return json($result, 201);
37	    }
38	
39	    /** GET /invoices/:id/receipt */
40	    public function receipt(Request $request): Response
41	    {
42	        $id = (int)$request->param('id');
43	        $user = AuthContext::user();
44	        return json(PaymentService::getReceipt($id, $user), 200);
45	    }
46	
47	    /** GET /exports/ledger?format=csv|xlsx */
48	    public function ledger(Request $request): Response
49	    {
50	        $traceId = \app\middleware\TraceId::getId();
51	        $user = AuthContext::user();
52	        $from = $request->get('from', '2020-01-01');
53	        $to = $request->get('to', date('Y-m-d'));
54	        $format = strtolower((string)$request->get('format', 'csv'));
55	        if (!in_array($format, ['csv', 'xlsx'], true)) {
56	            throw new \think\exception\HttpException(400, 'format must be csv or xlsx');
57	        }
58	
59	        $bytes = ExportService::ledger($user, $from, $to, $format, $traceId);
60	        return response($bytes, 200, self::exportHeaders($format, 'ledger'));
61	    }
62	
63	    /** GET /exports/reconciliation?format=csv|xlsx */
64	    public function reconciliation(Request $request): Response
65	    {
66	        $traceId = \app\middleware\TraceId::getId();
67	        $user = AuthContext::user();
68	        $from = $request->get('from', '2020-01-01');
69	        $to = $request->get('to', date('Y-m-d'));
70	        $format = strtolower((string)$request->get('format', 'csv'));
71	        if (!in_array($format, ['csv', 'xlsx'], true)) {
72	            throw new \think\exception\HttpException(400, 'format must be csv or xlsx');
73	        }
74	
75	        $bytes = ExportService::reconciliation($user, $from, $to, $format, $traceId);
76	        return response($bytes, 200, self::exportHeaders($format, 'reconciliation'));
77	    }
78	
79	    private static function exportHeaders(string $format, string $basename): array
80	    {
81	        if ($format === 'xlsx') {
82	            return [
83	                'Content-Type'        => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
84	                'Content-Disposition' => 'attachment; filename="' . $basename . '.xlsx"',
85	            ];
86	        }
87	        return [
88	            'Content-Type'        => 'text/csv',
89	            'Content-Disposition' => 'attachment; filename="' . $basename . '.csv"',
90	        ];
91	    }
92	}
