285	    private function makeUser(string $role, string $scope, int $scopeId): string
286	    {
287	        // Issue I-09: system_admin bootstrapped via PDO (public register refuses).
288	        if ($role === 'system_admin') {
289	            return $this->bootstrapAdmin('cov_' . substr($role, 0, 3), $scope, $scopeId)['token'];
290	        }
291	        $u = 'cov_' . substr($role, 0, 3) . '_' . bin2hex(random_bytes(4));
292	        $p = 'SecureP@ss1234';
293	        $this->post('/auth/register', ['username' => $u, 'password' => $p, 'role' => $role, 'geo_scope_level' => $scope, 'geo_scope_id' => $scopeId]);
294	        $r = $this->post('/auth/login', ['username' => $u, 'password' => $p]);
295	        return $r['data']['access_token'];
296	    }
