4	namespace app\middleware;
5	
6	use think\Request;
7	use think\Response;
8	use app\service\TokenService;
9	use think\facade\Db;
10	
11	/**
12	 * Authentication middleware for protected routes.
13	 * Validates Bearer token and attaches user data to the request.
14	 * Returns 401 if no/invalid token, 403 if role check fails.
15	 *
16	 * Usage in routes:
17	 *   ->middleware('authCheck')            // any authenticated user
18	 *   ->middleware('authCheck:system_admin') // require specific role
19	 */
20	class AuthCheck
21	{
22	    public function handle(Request $request, \Closure $next, ?string $requiredRole = null): Response
23	    {
24	        $traceId = \app\middleware\TraceId::getId();
25	
26	        // Extract Bearer token from $_SERVER directly
27	        // (ThinkPHP's $request->header() can lose headers after middleware processing)
28	        $authHeader = $_SERVER['HTTP_AUTHORIZATION'] ?? '';
29	        $token = '';
30	        if (str_starts_with($authHeader, 'Bearer ')) {
31	            $token = substr($authHeader, 7);
32	        }
33	
34	        if (empty($token)) {
35	            return $this->errorResponse(401, 'UNAUTHORIZED', 'Authentication required', $traceId);
36	        }
37	
38	        // Validate token
39	        $userId = TokenService::validate($token);
40	        if (!$userId) {
41	            return $this->errorResponse(401, 'UNAUTHORIZED', 'Invalid or expired token', $traceId);
42	        }
43	
44	        // Load user
45	        $user = Db::table('users')->where('id', $userId)->find();
46	        if (!$user || $user['status'] !== 'active') {
47	            return $this->errorResponse(401, 'UNAUTHORIZED', 'Account not active', $traceId);
48	        }
49	
50	        // Role check
51	        if ($requiredRole !== null && $user['role'] !== $requiredRole) {
52	            // Allow system_admin access to admin-level routes too
53	            $isAdmin = $user['role'] === 'system_admin';
54	            $adminRoutes = ['admin', 'system_admin'];
55	            if (!($isAdmin && in_array($requiredRole, $adminRoutes, true))) {
56	                return $this->errorResponse(403, 'FORBIDDEN', 'Insufficient permissions', $traceId);
57	            }
58	        }
59	
60	        // Store auth context for controllers to access (avoid PHP 8.2 dynamic property issues)
61	        \app\service\AuthContext::set([
62	            'id'              => (int)$user['id'],
63	            'username'        => $user['username'],
64	            'role'            => $user['role'],
65	            'geo_scope_level' => $user['geo_scope_level'],
66	            'geo_scope_id'    => (int)$user['geo_scope_id'],
67	            'status'          => $user['status'],
68	            'mfa_enabled'     => (bool)$user['mfa_enabled'],
69	        ], $token);
70	
71	        // Issue #12 remediation: capture request metadata (IP + UA) so that
72	        // service-layer audit callsites can log complete forensic context
73	        // without having to receive a Request object.
74	        $ip = $request->ip() ?: ($_SERVER['REMOTE_ADDR'] ?? '');
75	        $device = $_SERVER['HTTP_USER_AGENT'] ?? '';
76	        \app\service\RequestContext::set((string)$ip, (string)$device);
77	
78	        return $next($request);
79	    }
80	
81	    private function errorResponse(int $httpStatus, string $code, string $message, string $traceId): Response
82	    {
83	        return json([
84	            'status'   => 'error',
85	            'code'     => $code,
86	            'message'  => $message,
87	            'trace_id' => $traceId,
88	        ], $httpStatus)->header(['X-Trace-Id' => $traceId]);
89	    }
90	}
