96	    /**
97	     * Mark overdue invoices (unpaid past due date) and apply late fees.
98	     * Called by daily job or endpoint.
99	     *
100	     * Late-fee calculation is idempotent: fee = f(amount_cents, days_overdue)
101	     * so repeated job runs simply recalculate from the current date without
102	     * risk of double-applying.
103	     */
104	    public static function markOverdue(string $traceId = ''): int
105	    {
106	        $today = date('Y-m-d');
107	        $overdueInvoices = Db::table('invoices')
108	            ->where('status', 'unpaid')
109	            ->where('due_date', '<', $today)
110	            ->select()
111	            ->toArray();
112	
113	        $count = 0;
114	        foreach ($overdueInvoices as $inv) {
115	            try {
116	                self::transition((int)$inv['id'], 'overdue', $traceId);
117	                // Apply initial late fee on transition
118	                $daysOverdue = max(0, (int)((strtotime($today) - strtotime($inv['due_date'])) / 86400));
119	                $lateFee = LateFeeService::calculate((int)$inv['amount_cents'], $daysOverdue);
120	                Db::table('invoices')->where('id', $inv['id'])->update(['late_fee_cents' => $lateFee]);
121	                $count++;
122	            } catch (\Throwable $e) {
123	                // Skip already transitioned
124	            }
125	        }
126	
127	        // Recalculate late fees for ALL currently overdue invoices.
128	        // This handles daily accrual growth on repeat runs without double-applying,
129	        // because the fee is a pure function of (amount, days_overdue).
130	        self::updateLateFees($today, $traceId);
131	
132	        return $count;
133	    }
