6	/**
7	 * Shared helper for tests that need a system_admin account.
8	 *
9	 * After Issue I-09 remediation, public POST /auth/register refuses to
10	 * mint `system_admin` accounts — this is the intentional security
11	 * posture. Any test that needs an admin user now provisions one by
12	 * writing a row directly to the `users` table via PDO (a trust boundary
13	 * tests are allowed to cross), then performs a normal /auth/login to
14	 * obtain a bearer token.
15	 *
16	 * Usage (inside any test class):
17	 *
18	 *   use tests\AdminBootstrap;
19	 *
20	 *   class MyTest extends TestCase {
21	 *       use AdminBootstrap;
22	 *
23	 *       public function testSomething(): void {
24	 *           $admin = $this->bootstrapAdmin('myprefix');
25	 *           // $admin['token'] is a logged-in bearer token
26	 *       }
27	 *   }
28	 */
29	trait AdminBootstrap
30	{
31	    /**
32	     * Create a system_admin user directly in the DB and log in.
33	     *
34	     * @param string      $prefix        Username prefix for uniqueness
35	     * @param string      $scopeLevel    Geographic scope level
36	     * @param int         $scopeId       Geographic scope ID
37	     * @return array{username:string,password:string,id:int,token:string}
38	     */
39	    protected function bootstrapAdmin(string $prefix, string $scopeLevel = 'county', int $scopeId = 1): array
40	    {
41	        $username = 'tb_' . $prefix . '_' . bin2hex(random_bytes(4));
42	        $password = 'AdminP@ss12345';
43	        $hash = password_hash($password, PASSWORD_BCRYPT, ['cost' => 10]);
44	
45	        $pdo = $this->adminBootstrapPdo();
46	        $stmt = $pdo->prepare(
47	            'INSERT INTO users (username, password_hash, role, geo_scope_level, geo_scope_id, status, mfa_enabled) '
48	            . 'VALUES (?, ?, "system_admin", ?, ?, "active", 0)'
49	        );
50	        $stmt->execute([$username, $hash, $scopeLevel, $scopeId]);
51	        $userId = (int)$pdo->lastInsertId();
52	
53	        // Log in via the normal HTTP flow so the test exercises the real
54	        // token-issuance path. CAPTCHA is auto-solved.
55	        $baseUrl = getenv('API_BASE_URL') ?: 'http://localhost:8000';
56	        $captcha = $this->adminBootstrapSolveCaptcha($baseUrl);
57	        $ch = curl_init($baseUrl . '/auth/login');
58	        curl_setopt_array($ch, [
59	            CURLOPT_RETURNTRANSFER => true, CURLOPT_TIMEOUT => 10, CURLOPT_POST => true,
60	            CURLOPT_HTTPHEADER => ['Content-Type: application/json'],
61	            CURLOPT_POSTFIELDS => json_encode(array_merge(
62	                ['username' => $username, 'password' => $password],
63	                $captcha
64	            )),
65	        ]);
66	        $raw = curl_exec($ch);
67	        $status = curl_getinfo($ch, CURLINFO_HTTP_CODE);
68	        curl_close($ch);
69	        if ($status !== 200) {
70	            throw new \RuntimeException('Bootstrap admin login failed: ' . $raw);
71	        }
72	        $data = json_decode((string)$raw, true) ?: [];
73	        $token = $data['access_token'] ?? '';
74	        if ($token === '') {
75	            throw new \RuntimeException('Bootstrap admin login returned no access_token');
76	        }
77	
78	        return [
79	            'username' => $username,
80	            'password' => $password,
81	            'id'       => $userId,
82	            'token'    => $token,
83	        ];
84	    }
85	
86	    private function adminBootstrapPdo(): \PDO
87	    {
88	        static $pdo = null;
89	        if ($pdo === null) {
90	            $host = getenv('DB_HOST') ?: 'db';
91	            $port = getenv('DB_PORT') ?: '3306';
92	            $db   = getenv('DB_DATABASE') ?: 'rural_lease';
93	            $user = getenv('DB_USERNAME') ?: 'app';
94	            $pass = getenv('DB_PASSWORD') ?: 'app';
95	            $pdo = new \PDO(
96	                "mysql:host={$host};port={$port};dbname={$db};charset=utf8mb4",
97	                $user, $pass,
98	                [\PDO::ATTR_ERRMODE => \PDO::ERRMODE_EXCEPTION]
99	            );
100	        }
101	        return $pdo;
102	    }
103	
104	    private function adminBootstrapSolveCaptcha(string $baseUrl): array
105	    {
106	        $ch = curl_init($baseUrl . '/auth/captcha');
107	        curl_setopt_array($ch, [CURLOPT_RETURNTRANSFER => true, CURLOPT_TIMEOUT => 5]);
108	        $raw = curl_exec($ch); curl_close($ch);
109	        $d = json_decode((string)$raw, true) ?: [];
110	        $q = $d['question'] ?? '';
111	        if (preg_match('/(-?\d+)\s*([+\-*])\s*(-?\d+)/', $q, $m)) {
112	            $a = (int)$m[1]; $op = $m[2]; $b = (int)$m[3];
113	            $ans = match ($op) { '+' => $a + $b, '-' => $a - $b, '*' => $a * $b, default => 0 };
114	            return ['captcha_id' => $d['challenge_id'] ?? '', 'captcha_answer' => (string)$ans];
115	        }
116	        return ['captcha_id' => '', 'captcha_answer' => ''];
117	    }
118	}
