2	 * Base API client for the Rural Lease Portal.
3	 * Provides a thin wrapper over fetch() with:
4	 * - Automatic JSON parsing
5	 * - Auth token injection from localStorage
6	 * - Trace ID propagation
7	 * - Standardized error handling
8	 * - Auto-redirect to login on 401
9	 */
10	var ApiClient = (function () {
11	    'use strict';
12	
13	    var BASE_URL = '';  // Same origin
14	
15	    /**
16	     * Core request method.
17	     * @param {string} method - HTTP method
18	     * @param {string} path - API path (e.g., '/health')
19	     * @param {object} [options] - { body, headers, params }
20	     * @returns {Promise<{ok: boolean, status: number, data: object, traceId: string}>}
21	     */
22	    function request(method, path, options) {
23	        options = options || {};
24	        var headers = Object.assign({
25	            'Content-Type': 'application/json',
26	            'Accept': 'application/json'
27	        }, options.headers || {});
28	
29	        // Inject auth token if available
30	        var token = localStorage.getItem('access_token');
31	        if (token && !headers['Authorization']) {
32	            headers['Authorization'] = 'Bearer ' + token;
33	        }
34	
35	        var url = BASE_URL + path;
36	
37	        // Append query params for GET
38	        if (options.params) {
39	            var qs = Object.keys(options.params)
40	                .filter(function (k) { return options.params[k] !== undefined && options.params[k] !== null; })
41	                .map(function (k) { return encodeURIComponent(k) + '=' + encodeURIComponent(options.params[k]); })
42	                .join('&');
43	            if (qs) url += '?' + qs;
44	        }
45	
46	        var fetchOptions = {
47	            method: method,
48	            headers: headers
49	        };
50	
51	        if (options.body && method !== 'GET') {
52	            fetchOptions.body = JSON.stringify(options.body);
53	        }
54	
55	        return fetch(url, fetchOptions)
56	            .then(function (resp) {
57	                var traceId = resp.headers.get('X-Trace-Id') || '';
58	                return resp.json().then(function (data) {
59	                    return {
60	                        ok: resp.ok,
61	                        status: resp.status,
62	                        data: data,
63	                        traceId: traceId
64	                    };
65	                }).catch(function () {
66	                    return {
67	                        ok: resp.ok,
68	                        status: resp.status,
69	                        data: null,
70	                        traceId: traceId
71	                    };
72	                });
73	            })
74	            .catch(function (err) {
75	                return {
76	                    ok: false,
77	                    status: 0,
78	                    data: { status: 'error', code: 'NETWORK_ERROR', message: err.message, trace_id: '' },
79	                    traceId: ''
80	                };
81	            });
82	    }
83	
84	    return {
85	        get: function (path, params, headers) {
86	            return request('GET', path, { params: params, headers: headers });
87	        },
88	        post: function (path, body, headers) {
89	            return request('POST', path, { body: body, headers: headers });
90	        },
91	        patch: function (path, body, headers) {
92	            return request('PATCH', path, { body: body, headers: headers });
93	        },
94	        del: function (path, headers) {
95	            return request('DELETE', path, { headers: headers });
96	        },
97	
98	        /**
99	         * Health check convenience method.
100	         * @returns {Promise<{ok: boolean, status: string, traceId: string}>}
101	         */
102	        healthCheck: function () {
103	            return this.get('/health').then(function (resp) {
104	                return {
105	                    ok: resp.ok,
106	                    status: resp.data ? resp.data.status : 'unknown',
107	                    traceId: resp.traceId
108	                };
109	            });
110	        },
