157	    public static function getReceipt(int $invoiceId, array $user): array
158	    {
159	        $invoice = Db::table('invoices')->where('id', $invoiceId)->find();
160	        if (!$invoice) throw new \think\exception\HttpException(404, 'Invoice not found');
161	
162	        $contract = Db::table('contracts')->where('id', $invoice['contract_id'])->find();
163	        if (!$contract || !ScopeService::canAccess($user, $contract['geo_scope_level'], (int)$contract['geo_scope_id'])) {
164	            throw new \think\exception\HttpException(403, 'Outside your scope');
165	        }
166	
167	        $payments = Db::table('payments')->where('invoice_id', $invoiceId)->select()->toArray();
168	        $refunds = Db::table('refunds')->where('invoice_id', $invoiceId)->select()->toArray();
169	        $balanceCents = self::outstandingBalance($invoiceId);
170	        return ['invoice' => $invoice, 'contract' => $contract, 'payments' => $payments, 'refunds' => $refunds, 'balance_cents' => $balanceCents];
171	    }
