173	    /**
174	     * Canonical outstanding-balance formula used by payment and refund paths.
175	     * outstanding = invoice_amount + late_fee - totalPaid + totalRefunded
176	     */
177	    public static function outstandingBalance(int $invoiceId): int
178	    {
179	        $invoice = Db::table('invoices')->where('id', $invoiceId)->find();
180	        if (!$invoice) return 0;
181	        $totalPaid = (int)Db::table('payments')->where('invoice_id', $invoiceId)->sum('amount_cents');
182	        $totalRefunded = (int)Db::table('refunds')->where('invoice_id', $invoiceId)->sum('amount_cents');
183	        $balance = (int)$invoice['amount_cents'] + (int)($invoice['late_fee_cents'] ?? 0) - $totalPaid + $totalRefunded;
184	        return max($balance, 0);
185	    }
