31	            'resource_type'      => $resourceType,
32	            'resource_id'        => $resourceId,
33	            'before_json'        => $before ? json_encode($before) : null,
34	            'after_json'         => $after ? json_encode($after) : null,
35	            'ip'                 => $ip ?: null,
